import { withSupabaseHandler } from "../../utils/withSupabaseHandler.ts";
import { setGameQuestionIndex } from "../../../../../lib/games/set_game_question_index.js";

export default withSupabaseHandler(async (req, supabase) => {
  try {
    const { gameId, questionIndex } = await req.json();
    if (!gameId || questionIndex === undefined) {
      return new Response(JSON.stringify({ error: "Missing gameId or questionIndex" }), { status: 400 });
    }

    await setGameQuestionIndex(supabase, gameId, questionIndex);
    return new Response(JSON.stringify({ success: true }), { status: 200 });
  } catch (error) {
    return new Response(JSON.stringify({ error: error.message }), { status: 400 });
  }
});
